"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { ArrowRight, Fingerprint } from "lucide-react";
import { signInWithEmailAndPassword } from "firebase/auth";
import { auth } from "../_lib/firebase";

const ROLE_ROUTES: Record<string, string> = {
  guard:            "/guard",
  wh_manager:       "/manager",
  regional_manager: "/manager",
  cso:              "/cso",
  super_admin:      "/cso",
};

export function LoginForm() {
  const router = useRouter();
  const [email, setEmail]       = useState("");
  const [password, setPassword] = useState("");
  const [error, setError]       = useState<string | null>(null);
  const [loading, setLoading]   = useState(false);

  function routeFromEmail(emailAddr: string): string {
    const prefix = emailAddr.split("@")[0]?.toLowerCase() ?? "";
    if (prefix.startsWith("manager") || prefix.startsWith("wh_manager")) return "/manager";
    if (prefix.startsWith("cso") || prefix.startsWith("regional") || prefix.startsWith("super")) return "/cso";
    return "/guard"; // guard or any unknown role defaults to guard
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
      await signInWithEmailAndPassword(auth, email, password);
      router.push(routeFromEmail(email));
    } catch (err: unknown) {
      const msg =
        err instanceof Error
          ? err.message.replace("Firebase: ", "").replace(/ \(auth\/.*\)/, "")
          : "Sign-in failed";
      setError(msg);
    } finally {
      setLoading(false);
    }
  }

  return (
    <form className="space-y-4" onSubmit={handleSubmit}>
      <label className="block">
        <span className="mb-1.5 block text-[12.5px] font-medium text-slate-700">
          Work email
        </span>
        <input
          type="email"
          placeholder="you@yourcompany.com"
          autoComplete="email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
          className="h-11 w-full rounded-lg border border-slate-300 bg-white px-3.5 text-[14px] text-slate-900 placeholder:text-slate-400 focus:border-brand-500 focus:ring-4 focus:ring-brand-500/10"
        />
      </label>

      <label className="block">
        <span className="mb-1.5 block text-[12.5px] font-medium text-slate-700">
          Password
        </span>
        <input
          type="password"
          placeholder="••••••••"
          autoComplete="current-password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
          className="h-11 w-full rounded-lg border border-slate-300 bg-white px-3.5 text-[14px] text-slate-900 placeholder:text-slate-400 focus:border-brand-500 focus:ring-4 focus:ring-brand-500/10"
        />
      </label>

      {error && (
        <p className="rounded-lg border border-red-200 bg-red-50 px-3.5 py-2.5 text-[12.5px] text-red-700">
          {error}
        </p>
      )}

      <div className="flex items-center justify-between text-[12.5px]">
        <label className="inline-flex items-center gap-2 text-slate-600">
          <input type="checkbox" className="h-3.5 w-3.5 rounded border-slate-300" />
          Remember this terminal
        </label>
        <a href="#" className="font-semibold text-brand-700 hover:text-brand-800">
          Forgot password?
        </a>
      </div>

      <button
        type="submit"
        disabled={loading}
        className="group flex h-11 w-full items-center justify-center gap-2 rounded-lg bg-brand-800 text-[14px] font-semibold text-white shadow-sm ring-1 ring-brand-900/10 transition hover:bg-brand-700 disabled:opacity-60"
      >
        {loading ? "Signing in…" : "Sign in"}
        {!loading && <ArrowRight className="h-4 w-4 transition group-hover:translate-x-0.5" />}
      </button>

      <div className="relative py-3">
        <div className="absolute inset-0 flex items-center">
          <div className="w-full border-t border-slate-200" />
        </div>
        <div className="relative flex justify-center">
          <span className="bg-white px-3 text-[11px] font-semibold uppercase tracking-wider text-slate-400">
            or
          </span>
        </div>
      </div>

      <button
        type="button"
        className="flex h-11 w-full items-center justify-center gap-2 rounded-lg border border-slate-300 bg-white text-[13.5px] font-semibold text-slate-700 hover:bg-slate-50"
      >
        <Fingerprint className="h-4 w-4" />
        Sign in with SSO (SAML)
      </button>
    </form>
  );
}

