1	/**
2	 * FleetGuard — User service (DAL)
3	 * Reads/writes to fg_users collection only.
4	 */
5	
6	import {
7	  doc, getDoc, setDoc, updateDoc, addDoc, collection, query,
8	  where, getDocs, serverTimestamp,
9	} from "firebase/firestore";
10	import { db } from "../_lib/firebase";
11	import { assertFgPath, FG_USERS } from "../_lib/fg-paths";
12	import type { UserRole } from "../_lib/types";
13	
14	export interface FgUser {
15	  uid: string;
16	  email: string;
17	  displayName: string;
18	  role: UserRole;
19	  warehouseId: string;
20	  orgId: string;
21	  isActive: boolean;
22	  createdAt: Date;
23	  updatedAt: Date;
24	}
25	
26	type FgUserDoc = Omit<FgUser, "createdAt" | "updatedAt"> & {
27	  createdAt: { toDate(): Date } | null;
28	  updatedAt: { toDate(): Date } | null;
29	};
30	
31	function toFgUser(id: string, data: FgUserDoc): FgUser {
32	  return {
33	    ...data,
34	    uid: id,
35	    createdAt: data.createdAt?.toDate() ?? new Date(),
36	    updatedAt: data.updatedAt?.toDate() ?? new Date(),
37	  };
38	}
39	
40	export async function getUserById(uid: string): Promise<FgUser | null> {
41	  assertFgPath(FG_USERS);
42	  const snap = await getDoc(doc(db, FG_USERS, uid));
43	  if (!snap.exists()) return null;
44	  return toFgUser(snap.id, snap.data() as FgUserDoc);
45	}
