"use client";

/**
 * FleetGuard — RoleGuard
 * Wraps a route segment. Redirects away if the signed-in user's role
 * is not in the allowed list.
 *
 * Usage:
 *   <RoleGuard allowed={["wh_manager", "super_admin"]}>
 *     {children}
 *   </RoleGuard>
 */

import { useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "../_hooks/useAuth";
import type { UserRole } from "../_lib/types";

const ROLE_HOME: Record<UserRole, string> = {
  guard:            "/guard",
  wh_manager:       "/manager",
  regional_manager: "/manager",
  cso:              "/cso",
  company_admin:    "/company",
  super_admin:      "/superadmin",
};

interface Props {
  allowed: UserRole[];
  children: React.ReactNode;
}

export function RoleGuard({ allowed, children }: Props) {
  const { fgUser, loading } = useAuth();
  const router = useRouter();

  useEffect(() => {
    if (loading) return;

    // Not signed in — send to login
    if (!fgUser) {
      router.replace("/login");
      return;
    }

    // Wrong role — send to the correct home for their role
    if (!allowed.includes(fgUser.role)) {
      router.replace(ROLE_HOME[fgUser.role] ?? "/login");
    }
  }, [fgUser, loading, allowed, router]);

  if (loading) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-slate-50">
        <div className="text-[13px] text-slate-400">Loading…</div>
      </div>
    );
  }

  if (!fgUser || !allowed.includes(fgUser.role)) return null;

  return <>{children}</>;
}

"use client";

import { useEffect, useState } from "react";
import {
  ArrowRight,
  Building2,
  Globe2,
  Package,
  Plus,
  Users,
} from "lucide-react";
import Link from "next/link";
import { TopBar } from "../_components/TopBar";
import { PageHeader } from "../_components/PageHeader";
import { StatCard } from "../_components/StatCard";
import { Card, CardHeader } from "../_components/Card";
import { Badge } from "../_components/Badge";
import { Button } from "../_components/Button";
import { useAuth } from "../_hooks/useAuth";
import { fmtAgo } from "../_lib/utils";
import { getOrganisations, getAdminStats } from "../_services";
import type { FgOrganisation } from "../_services/organisationService";
import type { AdminStats } from "../_services/organisationService";

export default function SuperadminDashboard() {
  const { fgUser } = useAuth();

  const [orgs,    setOrgs]    = useState<FgOrganisation[]>([]);
  const [stats,   setStats]   = useState<AdminStats>({ orgCount: 0, userCount: 0, warehouseCount: 0, dealerCount: 0 });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([getOrganisations(), getAdminStats()])
      .then(([o, s]) => { setOrgs(o); setStats(s); })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const recentOrgs = [...orgs].sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime()).slice(0, 6);

  return (
    <>
      <TopBar breadcrumbs={[{ label: "Super Admin" }, { label: "Dashboard" }]} />
      <PageHeader
        eyebrow="System · All companies"
        title={`Welcome back${fgUser?.displayName ? `, ${fgUser.displayName}` : ""}`}
        subtitle="Full system oversight — manage companies, users, warehouses, dealers, and gates."
        actions={
          <Link href="/superadmin/companies">
            <Button size="sm" leftIcon={<Plus className="h-3.5 w-3.5" />}>
              New company
            </Button>
          </Link>
        }
      />

      <div className="flex-1 overflow-y-auto px-8 py-6">
        {loading ? (
          <p className="text-[13px] text-slate-500">Loading…</p>
        ) : (
          <>
            {/* KPI row */}
            <div className="grid grid-cols-2 gap-4 md:grid-cols-4">
              <StatCard label="Companies"  value={stats.orgCount}       icon={Building2} tone="brand"   hint="Registered organisations" />
              <StatCard label="Users"      value={stats.userCount}      icon={Users}     tone="default" hint="All roles, all companies"   />
              <StatCard label="Warehouses" value={stats.warehouseCount} icon={Globe2}    tone="info"    hint="Active FleetGuard sites"    />
              <StatCard label="Dealers"    value={stats.dealerCount}    icon={Package}   tone="success" hint="Registered delivery points"  />
            </div>

            {/* Quick-action cards */}
            <div className="mt-6 grid grid-cols-1 gap-4 md:grid-cols-3">
              {[
                { href: "/superadmin/companies",  icon: Building2, label: "Manage companies",  sub: "Create, edit, deactivate organisations" },
                { href: "/superadmin/companies",  icon: Users,     label: "Manage users",      sub: "Assign roles and warehouse access"      },
                { href: "/superadmin/account",    icon: Globe2,    label: "Account settings",  sub: "Update your profile and password"       },
              ].map((card) => {
                const Icon = card.icon;
                return (
                  <Link key={card.label} href={card.href}>
                    <div className="group flex items-center gap-4 rounded-xl border border-slate-200 bg-white p-5 shadow-xs transition hover:border-brand-300 hover:shadow-sm">
                      <div className="grid h-10 w-10 place-items-center rounded-lg bg-brand-50 text-brand-700 transition group-hover:bg-brand-100">
                        <Icon className="h-5 w-5" />
                      </div>
                      <div className="flex-1">
                        <div className="text-[13px] font-semibold text-slate-900">{card.label}</div>
                        <div className="mt-0.5 text-[12px] text-slate-500">{card.sub}</div>
                      </div>
                      <ArrowRight className="h-4 w-4 text-slate-300 group-hover:text-brand-600" />
                    </div>
                  </Link>
                );
              })}
            </div>

            {/* Recent companies */}
            <Card className="mt-6" padded={false}>
              <div className="flex items-center justify-between border-b border-slate-100 p-5">
                <CardHeader title="Recent companies" subtitle="Last added organisations" />
                <Link href="/superadmin/companies">
                  <Button variant="secondary" size="sm" rightIcon={<ArrowRight className="h-3.5 w-3.5" />}>
                    View all
                  </Button>
                </Link>
              </div>
              {recentOrgs.length === 0 ? (
                <div className="py-12 text-center">
                  <p className="text-[13px] text-slate-500">No companies yet.</p>
                  <Link href="/superadmin/companies">
                    <Button size="sm" className="mt-3" leftIcon={<Plus className="h-3.5 w-3.5" />}>
                      Add first company
                    </Button>
                  </Link>
                </div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead className="bg-slate-50 text-[10.5px] font-semibold uppercase tracking-wider text-slate-500">
                      <tr>
                        <th className="px-5 py-3">Company</th>
                        <th className="px-5 py-3">Code</th>
                        <th className="px-5 py-3">City, State</th>
                        <th className="px-5 py-3">Contact</th>
                        <th className="px-5 py-3">Status</th>
                        <th className="px-5 py-3">Created</th>
                        <th className="px-5 py-3 text-right" />
                      </tr>
                    </thead>
                    <tbody className="text-[13px]">
                      {recentOrgs.map((org) => (
                        <tr key={org.id} className="border-t border-slate-100 hover:bg-slate-50">
                          <td className="px-5 py-3 font-semibold text-slate-900">{org.name}</td>
                          <td className="px-5 py-3 font-mono text-[11px] text-slate-500">{org.shortCode}</td>
                          <td className="px-5 py-3 text-slate-600">{org.city}, {org.state}</td>
                          <td className="px-5 py-3 text-slate-600">{org.contactName}</td>
                          <td className="px-5 py-3">
                            <Badge tone={org.isActive ? "success" : "muted"} dot>
                              {org.isActive ? "Active" : "Inactive"}
                            </Badge>
                          </td>
                          <td className="px-5 py-3 text-[11px] text-slate-500">{fmtAgo(org.createdAt)}</td>
                          <td className="px-5 py-3 text-right">
                            <Link href={`/superadmin/companies/${org.id}`}>
                              <Button size="sm" variant="ghost" rightIcon={<ArrowRight className="h-3.5 w-3.5" />}>
                                Open
                              </Button>
                            </Link>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </Card>
          </>
        )}
      </div>
    </>
  );
}

