"use client";

/**
 * FleetGuard — useAuth hook
 * Tracks Firebase Auth state + fetches the user's FgUser profile from fg_users.
 */

import { useEffect, useState } from "react";
import { onAuthStateChanged, User, signInWithEmailAndPassword, signOut } from "firebase/auth";
import { auth } from "../_lib/firebase";
import { getUserById } from "../_services/userService";
import type { FgUser } from "../_services/userService";

export interface AuthState {
  firebaseUser: User | null;
  fgUser: FgUser | null;
  loading: boolean;
  error: string | null;
}

export function useAuth(): AuthState & {
  signIn: (email: string, password: string) => Promise<void>;
  logOut: () => Promise<void>;
} {
  const [state, setState] = useState<AuthState>({
    firebaseUser: null,
    fgUser: null,
    loading: true,
    error: null,
  });

  useEffect(() => {
    const unsub = onAuthStateChanged(auth, async (user) => {
      if (!user) {
        setState({ firebaseUser: null, fgUser: null, loading: false, error: null });
        return;
      }
      try {
        const fgUser = await getUserById(user.uid);
        setState({ firebaseUser: user, fgUser, loading: false, error: null });
      } catch (err: unknown) {
        const msg = err instanceof Error ? err.message : "Failed to load user profile";
        setState({ firebaseUser: user, fgUser: null, loading: false, error: msg });
      }
    });
    return unsub;
  }, []);

  async function signIn(email: string, password: string) {
    setState((s) => ({ ...s, loading: true, error: null }));
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : "Sign-in failed";
      setState((s) => ({ ...s, loading: false, error: msg }));
      throw err;
    }
  }

  async function logOut() {
    await signOut(auth);
  }

  return { ...state, signIn, logOut };
}

