/**
 * FleetGuard — Organisation service (DAL)
 * Reads/writes to fg_organisations. Super-admin operations only.
 */

import {
  collection, doc, getDoc, getDocs, addDoc, updateDoc,
  query, orderBy, serverTimestamp, Timestamp,
} from "firebase/firestore";
import { db } from "../_lib/firebase";
import {
  assertFgPath,
  FG_ORGANISATIONS,
  FG_USERS,
  FG_WAREHOUSES,
  FG_DEALERS,
} from "../_lib/fg-paths";

export interface FgOrganisation {
  id: string;
  name: string;
  shortCode: string;        // 2–8 uppercase chars, used as ID prefix
  contactName: string;
  contactEmail: string;
  contactPhone: string;
  address: string;
  city: string;
  state: string;
  isActive: boolean;
  createdAt: Date;
  updatedAt: Date;
}

type FgOrgDoc = Omit<FgOrganisation, "id" | "createdAt" | "updatedAt"> & {
  createdAt: Timestamp | null;
  updatedAt: Timestamp | null;
};

function toFgOrg(id: string, data: FgOrgDoc): FgOrganisation {
  return {
    ...data,
    id,
    createdAt: data.createdAt?.toDate() ?? new Date(),
    updatedAt: data.updatedAt?.toDate() ?? new Date(),
  };
}

export async function getOrganisations(): Promise<FgOrganisation[]> {
  assertFgPath(FG_ORGANISATIONS);
  const snap = await getDocs(query(collection(db, FG_ORGANISATIONS), orderBy("name")));
  return snap.docs.map((d) => toFgOrg(d.id, d.data() as FgOrgDoc));
}

export async function getOrganisationById(id: string): Promise<FgOrganisation | null> {
  assertFgPath(FG_ORGANISATIONS);
  const snap = await getDoc(doc(db, FG_ORGANISATIONS, id));
  if (!snap.exists()) return null;
  return toFgOrg(snap.id, snap.data() as FgOrgDoc);
}

export async function createOrganisation(
  data: Omit<FgOrganisation, "id" | "createdAt" | "updatedAt">,
): Promise<string> {
  assertFgPath(FG_ORGANISATIONS);
  const ref = await addDoc(collection(db, FG_ORGANISATIONS), {
    ...data,
    createdAt: serverTimestamp(),
    updatedAt: serverTimestamp(),
  });
  return ref.id;
}

export async function updateOrganisation(
  id: string,
  data: Partial<Omit<FgOrganisation, "id" | "createdAt" | "updatedAt">>,
): Promise<void> {
  assertFgPath(FG_ORGANISATIONS);
  await updateDoc(doc(db, FG_ORGANISATIONS, id), {
    ...data,
    updatedAt: serverTimestamp(),
  });
}

// ── Dashboard stats ──────────────────────────────────────────────────────────

export interface AdminStats {
  orgCount: number;
  userCount: number;
  warehouseCount: number;
  dealerCount: number;
}

export async function getAdminStats(): Promise<AdminStats> {
  assertFgPath(FG_ORGANISATIONS);
  assertFgPath(FG_USERS);
  assertFgPath(FG_WAREHOUSES);
  assertFgPath(FG_DEALERS);
  const [orgs, users, warehouses, dealers] = await Promise.all([
    getDocs(collection(db, FG_ORGANISATIONS)),
    getDocs(collection(db, FG_USERS)),
    getDocs(collection(db, FG_WAREHOUSES)),
    getDocs(collection(db, FG_DEALERS)),
  ]);
  return {
    orgCount:       orgs.size,
    userCount:      users.size,
    warehouseCount: warehouses.size,
    dealerCount:    dealers.size,
  };
}

