"use client";

import { useEffect, useState } from "react";
import {
  ArrowRight,
  Building2,
  CheckCircle2,
  Pencil,
  Plus,
  Search,
  XCircle,
} from "lucide-react";
import Link from "next/link";
import { TopBar } from "../../_components/TopBar";
import { PageHeader } from "../../_components/PageHeader";
import { Card } from "../../_components/Card";
import { StatCard } from "../../_components/StatCard";
import { Badge } from "../../_components/Badge";
import { Button } from "../../_components/Button";
import { SlidePanel, Field, inputCls } from "../../_components/SlidePanel";
import { useAuth } from "../../_hooks/useAuth";
import { fmtAgo } from "../../_lib/utils";
import {
  getOrganisations,
  createOrganisation,
  updateOrganisation,
} from "../../_services";
import type { FgOrganisation } from "../../_services/organisationService";

const INDIA_STATES = [
  "Andhra Pradesh","Arunachal Pradesh","Assam","Bihar","Chhattisgarh","Goa",
  "Gujarat","Haryana","Himachal Pradesh","Jharkhand","Karnataka","Kerala",
  "Madhya Pradesh","Maharashtra","Manipur","Meghalaya","Mizoram","Nagaland",
  "Odisha","Punjab","Rajasthan","Sikkim","Tamil Nadu","Telangana","Tripura",
  "Uttar Pradesh","Uttarakhand","West Bengal","Delhi","Jammu & Kashmir",
  "Ladakh","Puducherry",
];

const BLANK = {
  name: "", shortCode: "", contactName: "", contactEmail: "",
  contactPhone: "", address: "", city: "", state: "", isActive: true,
};

type FormState = typeof BLANK;

export default function CompaniesPage() {
  const { fgUser } = useAuth();

  const [orgs,     setOrgs]     = useState<FgOrganisation[]>([]);
  const [loading,  setLoading]  = useState(true);
  const [search,   setSearch]   = useState("");
  const [filter,   setFilter]   = useState<"all" | "active" | "inactive">("all");

  const [panelOpen, setPanelOpen] = useState(false);
  const [editing,   setEditing]   = useState<FgOrganisation | null>(null);
  const [form,      setForm]      = useState<FormState>(BLANK);
  const [errors,    setErrors]    = useState<Partial<FormState>>({});
  const [saving,    setSaving]    = useState(false);

  const load = () => {
    setLoading(true);
    getOrganisations()
      .then(setOrgs)
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  useEffect(load, []);

  function openCreate() {
    setEditing(null);
    setForm(BLANK);
    setErrors({});
    setPanelOpen(true);
  }

  function openEdit(org: FgOrganisation) {
    setEditing(org);
    setForm({
      name: org.name, shortCode: org.shortCode, contactName: org.contactName,
      contactEmail: org.contactEmail, contactPhone: org.contactPhone,
      address: org.address, city: org.city, state: org.state, isActive: org.isActive,
    });
    setErrors({});
    setPanelOpen(true);
  }

  function validate(): boolean {
    const e: Partial<FormState> = {};
    if (!form.name.trim())      e.name      = "Required";
    if (!form.shortCode.trim()) e.shortCode = "Required";
    if (!form.city.trim())      e.city      = "Required";
    if (!form.state)            e.state     = "Required";
    setErrors(e);
    return Object.keys(e).length === 0;
  }

  async function save() {
    if (!validate()) return;
    setSaving(true);
    try {
      const data = { ...form, shortCode: form.shortCode.toUpperCase().trim() };
      if (editing) {
        await updateOrganisation(editing.id, data);
      } else {
        await createOrganisation(data);
      }
      setPanelOpen(false);
      load();
    } catch (err) {
      console.error(err);
    } finally {
      setSaving(false);
    }
  }

  async function toggleActive(org: FgOrganisation) {
    await updateOrganisation(org.id, { isActive: !org.isActive });
    load();
  }

  const filtered = orgs
    .filter((o) =>
      filter === "all" ? true : filter === "active" ? o.isActive : !o.isActive,
    )
    .filter((o) => {
      const q = search.toLowerCase();
      return (
        o.name.toLowerCase().includes(q) ||
        o.shortCode.toLowerCase().includes(q) ||
        o.city.toLowerCase().includes(q)
      );
    });

  const activeCount   = orgs.filter((o) =>  o.isActive).length;
  const inactiveCount = orgs.filter((o) => !o.isActive).length;

  return (
    <>
      <TopBar breadcrumbs={[{ label: "Super Admin", href: "/superadmin" }, { label: "Companies" }]} />
      <PageHeader
        eyebrow="Administration · All companies"
        title="Companies"
        subtitle="Every organisation registered in FleetGuard. Each company has its own users, warehouses, and dealers."
        actions={
          <Button size="sm" leftIcon={<Plus className="h-3.5 w-3.5" />} onClick={openCreate}>
            New company
          </Button>
        }
      />

      <div className="flex-1 overflow-y-auto px-8 py-6">
        {/* KPIs */}
        <div className="grid grid-cols-3 gap-4">
          <StatCard label="Total"    value={orgs.length}   icon={Building2}    tone="brand"   />
          <StatCard label="Active"   value={activeCount}   icon={CheckCircle2} tone="success" />
          <StatCard label="Inactive" value={inactiveCount} icon={XCircle}      tone="muted"   />
        </div>

        {/* Search + filter */}
        <div className="mt-6 flex flex-wrap items-center justify-between gap-3 rounded-xl border border-slate-200 bg-white p-4 shadow-xs">
          <div className="relative w-full max-w-sm">
            <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400" />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search by name, code or city…"
              className="h-10 w-full rounded-lg border border-slate-200 bg-slate-50 pl-9 pr-3 text-[13px] focus:border-brand-500 focus:bg-white focus:outline-none focus:ring-4 focus:ring-brand-500/10"
            />
          </div>
          <div className="flex items-center gap-2 text-[12px]">
            {(["all", "active", "inactive"] as const).map((f) => (
              <button
                key={f}
                type="button"
                onClick={() => setFilter(f)}
                className={`rounded-full px-3 py-1 font-semibold capitalize ${
                  filter === f
                    ? "bg-brand-800 text-white"
                    : "bg-slate-100 text-slate-700 hover:bg-slate-200"
                }`}
              >
                {f}
              </button>
            ))}
          </div>
        </div>

        {/* Table */}
        <Card className="mt-4" padded={false}>
          {loading ? (
            <p className="py-10 text-center text-[13px] text-slate-500">Loading…</p>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-[10.5px] font-semibold uppercase tracking-wider text-slate-500">
                  <tr>
                    <th className="px-5 py-3">Company</th>
                    <th className="px-5 py-3">Code</th>
                    <th className="px-5 py-3">City, State</th>
                    <th className="px-5 py-3">Contact</th>
                    <th className="px-5 py-3">Status</th>
                    <th className="px-5 py-3">Created</th>
                    <th className="px-5 py-3 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="text-[13px]">
                  {filtered.length === 0 ? (
                    <tr>
                      <td colSpan={7} className="py-12 text-center text-[13px] text-slate-500">
                        No companies found. Click "New company" to add the first one.
                      </td>
                    </tr>
                  ) : filtered.map((org) => (
                    <tr key={org.id} className="border-t border-slate-100 hover:bg-slate-50">
                      <td className="px-5 py-4">
                        <div className="flex items-center gap-3">
                          <div className="grid h-9 w-9 place-items-center rounded-lg bg-brand-50 text-brand-700 ring-1 ring-brand-100">
                            <Building2 className="h-4 w-4" />
                          </div>
                          <span className="font-semibold text-slate-900">{org.name}</span>
                        </div>
                      </td>
                      <td className="px-5 py-4 font-mono text-[11px] text-slate-500">{org.shortCode}</td>
                      <td className="px-5 py-4 text-slate-600">{org.city}, {org.state}</td>
                      <td className="px-5 py-4">
                        <div className="text-slate-800">{org.contactName}</div>
                        <div className="text-[11px] text-slate-500">{org.contactEmail}</div>
                      </td>
                      <td className="px-5 py-4">
                        <Badge tone={org.isActive ? "success" : "muted"} dot>
                          {org.isActive ? "Active" : "Inactive"}
                        </Badge>
                      </td>
                      <td className="px-5 py-4 text-[11px] text-slate-500">{fmtAgo(org.createdAt)}</td>
                      <td className="px-5 py-4 text-right">
                        <div className="inline-flex items-center gap-2">
                          <Button size="sm" variant="ghost" leftIcon={<Pencil className="h-3.5 w-3.5" />} onClick={() => openEdit(org)}>
                            Edit
                          </Button>
                          <Button
                            size="sm"
                            variant={org.isActive ? "ghost" : "success"}
                            onClick={() => toggleActive(org)}
                          >
                            {org.isActive ? "Deactivate" : "Activate"}
                          </Button>
                          <Link href={`/superadmin/companies/${org.id}`}>
                            <Button size="sm" variant="secondary" rightIcon={<ArrowRight className="h-3.5 w-3.5" />}>
                              Open
                            </Button>
                          </Link>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
          <div className="border-t border-slate-100 px-5 py-3 text-[11.5px] text-slate-500">
            Showing {filtered.length} of {orgs.length} companies
          </div>
        </Card>
      </div>

      {/* Create / Edit panel */}
      <SlidePanel
        open={panelOpen}
        onClose={() => setPanelOpen(false)}
        title={editing ? "Edit company" : "New company"}
        subtitle={editing ? `Editing ${editing.name}` : "Register a new organisation in FleetGuard"}
      >
        <div className="space-y-4">
          <Field label="Company name" required error={errors.name}>
            <input className={inputCls(errors.name)} value={form.name} onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))} placeholder="e.g. Reliance Retail Ltd." />
          </Field>

          <Field label="Short code" required error={errors.shortCode}>
            <input className={inputCls(errors.shortCode)} value={form.shortCode} onChange={(e) => setForm((f) => ({ ...f, shortCode: e.target.value.toUpperCase() }))} placeholder="e.g. RRL" maxLength={8} />
            <p className="text-[11px] text-slate-400">2–8 uppercase letters. Used as a prefix in IDs.</p>
          </Field>

          <div className="grid grid-cols-2 gap-3">
            <Field label="Contact name">
              <input className={inputCls()} value={form.contactName} onChange={(e) => setForm((f) => ({ ...f, contactName: e.target.value }))} placeholder="Primary contact" />
            </Field>
            <Field label="Contact phone">
              <input className={inputCls()} value={form.contactPhone} onChange={(e) => setForm((f) => ({ ...f, contactPhone: e.target.value }))} placeholder="+91 98XXX XXXXX" />
            </Field>
          </div>

          <Field label="Contact email">
            <input type="email" className={inputCls()} value={form.contactEmail} onChange={(e) => setForm((f) => ({ ...f, contactEmail: e.target.value }))} placeholder="contact@company.com" />
          </Field>

          <Field label="Address">
            <input className={inputCls()} value={form.address} onChange={(e) => setForm((f) => ({ ...f, address: e.target.value }))} placeholder="Street / locality" />
          </Field>

          <div className="grid grid-cols-2 gap-3">
            <Field label="City" required error={errors.city}>
              <input className={inputCls(errors.city)} value={form.city} onChange={(e) => setForm((f) => ({ ...f, city: e.target.value }))} placeholder="City" />
            </Field>
            <Field label="State" required error={errors.state}>
              <select className={inputCls(errors.state)} value={form.state} onChange={(e) => setForm((f) => ({ ...f, state: e.target.value }))}>
                <option value="">Select state</option>
                {INDIA_STATES.map((s) => <option key={s} value={s}>{s}</option>)}
              </select>
            </Field>
          </div>

          <div className="flex items-center gap-3 rounded-lg border border-slate-200 bg-slate-50 px-4 py-3">
            <input
              id="isActive"
              type="checkbox"
              className="h-4 w-4 rounded border-slate-300 text-brand-600"
              checked={form.isActive}
              onChange={(e) => setForm((f) => ({ ...f, isActive: e.target.checked }))}
            />
            <label htmlFor="isActive" className="text-[13px] font-medium text-slate-700">
              Company is active
            </label>
          </div>

          <div className="flex gap-3 pt-2">
            <Button full size="md" onClick={save} disabled={saving}>
              {saving ? "Saving…" : editing ? "Save changes" : "Create company"}
            </Button>
            <Button full size="md" variant="secondary" onClick={() => setPanelOpen(false)}>
              Cancel
            </Button>
          </div>
        </div>
      </SlidePanel>
    </>
  );
}

