"use client";

import { useEffect, useState } from "react";
import { Pencil, Plus, Search, UserX } from "lucide-react";
import { TopBar } from "../../_components/TopBar";
import { Card } from "../../_components/Card";
import { Badge } from "../../_components/Badge";
import { Button } from "../../_components/Button";
import { Avatar } from "../../_components/Avatar";
import { SlidePanel, Field, inputCls } from "../../_components/SlidePanel";
import { PageHeader } from "../../_components/PageHeader";
import { fmtDate } from "../../_lib/utils";
import { useAuth } from "../../_hooks/useAuth";
import {
  getUsersByOrg, createUserRecord, updateUser, deactivateUser, getWarehousesByOrg,
} from "../../_services";
import type { FgUser }      from "../../_services/userService";
import type { UserRole }    from "../../_lib/types";

/* Company admins can manage these roles — not company_admin (superadmin only) */
const ROLES: { value: UserRole; label: string }[] = [
  { value: "guard",            label: "Guard"             },
  { value: "wh_manager",       label: "Warehouse Manager" },
  { value: "regional_manager", label: "Regional Manager"  },
  { value: "cso",              label: "CSO"               },
];

const ROLE_TONE: Record<string, "info" | "brand" | "warning" | "success" | "danger" | "muted"> = {
  guard:            "info",
  wh_manager:       "brand",
  regional_manager: "warning",
  cso:              "success",
  company_admin:    "danger",
};

const BLANK = { displayName: "", email: "", role: "guard" as UserRole, warehouseId: "", orgId: "", isActive: true };

export default function CompanyUsersPage() {
  const { fgUser } = useAuth();
  const orgId = fgUser?.orgId ?? "";

  const [users,      setUsers]      = useState<FgUser[]>([]);
  const [warehouses, setWarehouses] = useState<{ id: string; name: string }[]>([]);
  const [loading,    setLoading]    = useState(true);
  const [search,     setSearch]     = useState("");

  const [panelOpen, setPanelOpen] = useState(false);
  const [editing,   setEditing]   = useState<FgUser | null>(null);
  const [form,      setForm]      = useState(BLANK);
  const [errors,    setErrors]    = useState<Partial<typeof BLANK>>({});
  const [saving,    setSaving]    = useState(false);

  const load = () => {
    if (!orgId) return;
    setLoading(true);
    Promise.all([getUsersByOrg(orgId), getWarehousesByOrg(orgId)])
      .then(([u, w]) => { setUsers(u); setWarehouses(w.map((wh) => ({ id: wh.id, name: wh.name }))); })
      .catch(console.error)
      .finally(() => setLoading(false));
  };
  useEffect(load, [orgId]);

  function openCreate() { setEditing(null); setForm({ ...BLANK, orgId }); setErrors({}); setPanelOpen(true); }

  function openEdit(user: FgUser) {
    setEditing(user);
    setForm({ displayName: user.displayName, email: user.email, role: user.role as UserRole, warehouseId: user.warehouseId, orgId: user.orgId, isActive: user.isActive });
    setErrors({}); setPanelOpen(true);
  }

  function validate() {
    const e: Partial<typeof BLANK> = {};
    if (!form.displayName.trim()) e.displayName = "Required";
    if (!form.email.trim())       e.email       = "Required";
    setErrors(e);
    return Object.keys(e).length === 0;
  }

  async function save() {
    if (!validate()) return;
    setSaving(true);
    try {
      if (editing) {
        await updateUser(editing.uid, { displayName: form.displayName, role: form.role, warehouseId: form.warehouseId, isActive: form.isActive });
      } else {
        await createUserRecord({ displayName: form.displayName, email: form.email, role: form.role, warehouseId: form.warehouseId, orgId, isActive: true });
      }
      setPanelOpen(false); load();
    } catch (err) { console.error(err); }
    finally { setSaving(false); }
  }

  const filtered = users.filter((u) => {
    const q = search.toLowerCase();
    return u.displayName.toLowerCase().includes(q) || u.email.toLowerCase().includes(q) || u.role.toLowerCase().includes(q);
  });

  return (
    <>
      <TopBar breadcrumbs={[{ label: "My Company", href: "/company" }, { label: "Users" }]} />
      <PageHeader eyebrow="Manage · Users" title="Users" subtitle="All user accounts for your company." />

      <div className="flex-1 overflow-y-auto px-8 py-6">
        <div className="flex flex-wrap items-center justify-between gap-3 rounded-xl border border-slate-200 bg-white p-4 shadow-xs">
          <div className="relative w-full max-w-sm">
            <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400" />
            <input value={search} onChange={(e) => setSearch(e.target.value)} placeholder="Search by name, email or role…"
              className="h-10 w-full rounded-lg border border-slate-200 bg-slate-50 pl-9 pr-3 text-[13px] focus:border-brand-500 focus:bg-white focus:outline-none focus:ring-4 focus:ring-brand-500/10" />
          </div>
          <Button size="sm" leftIcon={<Plus className="h-3.5 w-3.5" />} onClick={openCreate}>Add user</Button>
        </div>

        <Card className="mt-4" padded={false}>
          {loading ? <p className="py-10 text-center text-[13px] text-slate-500">Loading…</p> : (
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-[10.5px] font-semibold uppercase tracking-wider text-slate-500">
                  <tr>
                    <th className="px-5 py-3">User</th>
                    <th className="px-5 py-3">Role</th>
                    <th className="px-5 py-3">Warehouse</th>
                    <th className="px-5 py-3">Status</th>
                    <th className="px-5 py-3">Created</th>
                    <th className="px-5 py-3 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="text-[13px]">
                  {filtered.length === 0 ? (
                    <tr><td colSpan={6} className="py-12 text-center text-[13px] text-slate-500">No users yet.</td></tr>
                  ) : filtered.map((user) => (
                    <tr key={user.uid} className="border-t border-slate-100 hover:bg-slate-50">
                      <td className="px-5 py-4">
                        <div className="flex items-center gap-3">
                          <Avatar name={user.displayName} size="sm" />
                          <div>
                            <div className="font-semibold text-slate-900">{user.displayName}</div>
                            <div className="text-[11px] text-slate-500">{user.email}</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-5 py-4">
                        <Badge tone={ROLE_TONE[user.role] ?? "muted"}>
                          {ROLES.find((r) => r.value === user.role)?.label ?? user.role}
                        </Badge>
                      </td>
                      <td className="px-5 py-4 font-mono text-[11px] text-slate-500">
                        {warehouses.find((w) => w.id === user.warehouseId)?.name ?? (user.warehouseId || "—")}
                      </td>
                      <td className="px-5 py-4">
                        <Badge tone={user.isActive ? "success" : "muted"} dot>{user.isActive ? "Active" : "Inactive"}</Badge>
                      </td>
                      <td className="px-5 py-4 text-[11px] text-slate-500">{fmtDate(user.createdAt)}</td>
                      <td className="px-5 py-4 text-right">
                        <div className="inline-flex items-center gap-2">
                          <Button size="sm" variant="ghost" leftIcon={<Pencil className="h-3.5 w-3.5" />} onClick={() => openEdit(user)}>Edit</Button>
                          {user.isActive && user.role !== "company_admin" && (
                            <Button size="sm" variant="ghost" leftIcon={<UserX className="h-3.5 w-3.5" />} onClick={() => deactivateUser(user.uid).then(load)}>Deactivate</Button>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
          <div className="border-t border-slate-100 px-5 py-3 text-[11.5px] text-slate-500">{filtered.length} user{filtered.length !== 1 ? "s" : ""} shown</div>
        </Card>
      </div>

      <SlidePanel open={panelOpen} onClose={() => setPanelOpen(false)} title={editing ? "Edit user" : "Add user"}
        subtitle={editing ? `Editing ${editing.displayName}` : "Create a user account for your company"}>
        <div className="space-y-4">
          <Field label="Full name" required error={errors.displayName}>
            <input className={inputCls(errors.displayName)} value={form.displayName} onChange={(e) => setForm((f) => ({ ...f, displayName: e.target.value }))} placeholder="John Doe" />
          </Field>
          {!editing && (
            <Field label="Email address" required error={errors.email}>
              <input type="email" className={inputCls(errors.email)} value={form.email} onChange={(e) => setForm((f) => ({ ...f, email: e.target.value }))} placeholder="user@company.com" />
            </Field>
          )}
          <Field label="Role" required>
            <select className={inputCls()} value={form.role} onChange={(e) => setForm((f) => ({ ...f, role: e.target.value as UserRole }))}>
              {ROLES.map((r) => <option key={r.value} value={r.value}>{r.label}</option>)}
            </select>
          </Field>
          <Field label="Assigned warehouse">
            <select className={inputCls()} value={form.warehouseId} onChange={(e) => setForm((f) => ({ ...f, warehouseId: e.target.value }))}>
              <option value="">— No warehouse —</option>
              {warehouses.map((w) => <option key={w.id} value={w.id}>{w.name}</option>)}
            </select>
          </Field>
          {editing && (
            <div className="flex items-center gap-3 rounded-lg border border-slate-200 bg-slate-50 px-4 py-3">
              <input id="uActive" type="checkbox" className="h-4 w-4 rounded border-slate-300" checked={form.isActive} onChange={(e) => setForm((f) => ({ ...f, isActive: e.target.checked }))} />
              <label htmlFor="uActive" className="text-[13px] font-medium text-slate-700">User is active</label>
            </div>
          )}
          <div className="flex gap-3 pt-2">
            <Button full size="md" onClick={save} disabled={saving}>{saving ? "Saving…" : editing ? "Save changes" : "Create user"}</Button>
            <Button full size="md" variant="secondary" onClick={() => setPanelOpen(false)}>Cancel</Button>
          </div>
        </div>
      </SlidePanel>
    </>
  );
}

