1	/**
2	 * FleetGuard — Firebase Admin SDK initialisation
3	 *
4	 * IMPORT BOUNDARY (brief rule 8 + safety rule S8):
5	 *   This file may ONLY be imported inside app/api/[route]/route.ts files.
6	 *   NEVER import this from components, pages, hooks, or services.
7	 *
8	 * The ESLint rule in eslint.config.mjs enforces this at build time.
9	 */
10	
11	import { initializeApp, getApps, cert } from "firebase-admin/app";
12	import type { App } from "firebase-admin/app";
13	import { getFirestore } from "firebase-admin/firestore";
14	import type { Firestore } from "firebase-admin/firestore";
15	import { getAuth } from "firebase-admin/auth";
16	import type { Auth } from "firebase-admin/auth";
17	
18	function createAdminApp(): App {
19	  if (getApps().length > 0) return getApps()[0]!;
20	
21	  const projectId   = process.env.FIREBASE_ADMIN_PROJECT_ID;
22	  const clientEmail = process.env.FIREBASE_ADMIN_CLIENT_EMAIL;
23	  const privateKey  = process.env.FIREBASE_ADMIN_PRIVATE_KEY?.replace(/\\n/g, "\n");
24	
25	  if (!projectId || !clientEmail || !privateKey) {
26	    if ((process.env.TRIP_SOURCE ?? "mock") !== "mock") {
27	      throw new Error(
28	        "Firebase Admin SDK credentials are not configured. " +
29	          "Set FIREBASE_ADMIN_PROJECT_ID, FIREBASE_ADMIN_CLIENT_EMAIL, " +
30	          "and FIREBASE_ADMIN_PRIVATE_KEY in .env.local"
31	      );
32	    }
33	    return initializeApp({ projectId: "mock-project" });
34	  }
35	
36	  return initializeApp({
37	    credential: cert({ projectId, clientEmail, privateKey }),
38	  });
39	}
40	
41	const adminApp = createAdminApp();
42	
43	export const adminDb:   Firestore = getFirestore(adminApp);
