/**
 * FleetGuard — Warehouse service (DAL)
 * Reads/writes to fg_warehouses collection.
 * This service defines the full FgWarehouse type.
 * The useWarehouse hook defines its own minimal FgWarehouse — both are valid.
 */

import {
  collection, doc, getDoc, getDocs, addDoc, updateDoc,
  query, where, orderBy, serverTimestamp, Timestamp,
} from "firebase/firestore";
import { db } from "../_lib/firebase";
import { assertFgPath, FG_WAREHOUSES } from "../_lib/fg-paths";

export interface FgWarehouse {
  id: string;
  name: string;
  code: string;             // e.g. "BHW-01"
  address: string;
  city: string;
  state: string;
  region: string;
  orgId: string;
  managerId: string | null; // fg_users uid of assigned manager
  isActive: boolean;
  lat: number | null;
  lng: number | null;
  createdAt: Date;
  updatedAt: Date;
}

type FgWarehouseDoc = Omit<FgWarehouse, "id" | "createdAt" | "updatedAt"> & {
  createdAt: Timestamp | null;
  updatedAt: Timestamp | null;
};

function toFgWarehouse(id: string, data: FgWarehouseDoc): FgWarehouse {
  return {
    ...data,
    id,
    createdAt: data.createdAt?.toDate() ?? new Date(),
    updatedAt: data.updatedAt?.toDate() ?? new Date(),
  };
}

export async function getWarehousesByOrg(orgId: string): Promise<FgWarehouse[]> {
  assertFgPath(FG_WAREHOUSES);
  const q = query(
    collection(db, FG_WAREHOUSES),
    where("orgId", "==", orgId),
    orderBy("name"),
  );
  const snap = await getDocs(q);
  return snap.docs.map((d) => toFgWarehouse(d.id, d.data() as FgWarehouseDoc));
}

export async function getWarehouseById(id: string): Promise<FgWarehouse | null> {
  assertFgPath(FG_WAREHOUSES);
  const snap = await getDoc(doc(db, FG_WAREHOUSES, id));
  if (!snap.exists()) return null;
  return toFgWarehouse(snap.id, snap.data() as FgWarehouseDoc);
}

export async function createWarehouse(
  data: Omit<FgWarehouse, "id" | "createdAt" | "updatedAt">,
): Promise<string> {
  assertFgPath(FG_WAREHOUSES);
  const ref = await addDoc(collection(db, FG_WAREHOUSES), {
    ...data,
    createdAt: serverTimestamp(),
    updatedAt: serverTimestamp(),
  });
  return ref.id;
}

export async function updateWarehouse(
  id: string,
  data: Partial<Omit<FgWarehouse, "id" | "orgId" | "createdAt" | "updatedAt">>,
): Promise<void> {
  assertFgPath(FG_WAREHOUSES);
  await updateDoc(doc(db, FG_WAREHOUSES, id), {
    ...data,
    updatedAt: serverTimestamp(),
  });
}

export async function deactivateWarehouse(id: string): Promise<void> {
  assertFgPath(FG_WAREHOUSES);
  await updateDoc(doc(db, FG_WAREHOUSES, id), {
    isActive: false,
    updatedAt: serverTimestamp(),
  });
}

