/**
 * FleetGuard — Warehouse Gate service (DAL)
 * Reads/writes to fg_warehouse_gates collection.
 */

import {
  collection, doc, getDoc, getDocs, addDoc, updateDoc,
  query, where, orderBy, serverTimestamp, Timestamp,
} from "firebase/firestore";
import { db } from "../_lib/firebase";
import { assertFgPath, FG_WAREHOUSE_GATES } from "../_lib/fg-paths";

export type GateType = "entry" | "exit" | "both";

export interface FgWarehouseGate {
  id: string;
  name: string;           // "Main Gate", "Gate 1", "Service Entry"
  gateCode: string;       // "MG", "G1", "SE"
  gateType: GateType;
  warehouseId: string;
  orgId: string;
  isActive: boolean;
  notes: string | null;
  createdAt: Date;
  updatedAt: Date;
}

type FgGateDoc = Omit<FgWarehouseGate, "id" | "createdAt" | "updatedAt"> & {
  createdAt: Timestamp | null;
  updatedAt: Timestamp | null;
};

function toFgGate(id: string, data: FgGateDoc): FgWarehouseGate {
  return {
    ...data,
    id,
    createdAt: data.createdAt?.toDate() ?? new Date(),
    updatedAt: data.updatedAt?.toDate() ?? new Date(),
  };
}

export async function getGatesByWarehouse(warehouseId: string): Promise<FgWarehouseGate[]> {
  assertFgPath(FG_WAREHOUSE_GATES);
  const q = query(
    collection(db, FG_WAREHOUSE_GATES),
    where("warehouseId", "==", warehouseId),
    orderBy("name"),
  );
  const snap = await getDocs(q);
  return snap.docs.map((d) => toFgGate(d.id, d.data() as FgGateDoc));
}

export async function getGatesByOrg(orgId: string): Promise<FgWarehouseGate[]> {
  assertFgPath(FG_WAREHOUSE_GATES);
  const q = query(
    collection(db, FG_WAREHOUSE_GATES),
    where("orgId", "==", orgId),
    orderBy("name"),
  );
  const snap = await getDocs(q);
  return snap.docs.map((d) => toFgGate(d.id, d.data() as FgGateDoc));
}

export async function getGateById(id: string): Promise<FgWarehouseGate | null> {
  assertFgPath(FG_WAREHOUSE_GATES);
  const snap = await getDoc(doc(db, FG_WAREHOUSE_GATES, id));
  if (!snap.exists()) return null;
  return toFgGate(snap.id, snap.data() as FgGateDoc);
}

export async function createGate(
  data: Omit<FgWarehouseGate, "id" | "createdAt" | "updatedAt">,
): Promise<string> {
  assertFgPath(FG_WAREHOUSE_GATES);
  const ref = await addDoc(collection(db, FG_WAREHOUSE_GATES), {
    ...data,
    createdAt: serverTimestamp(),
    updatedAt: serverTimestamp(),
  });
  return ref.id;
}

export async function updateGate(
  id: string,
  data: Partial<Omit<FgWarehouseGate, "id" | "warehouseId" | "orgId" | "createdAt" | "updatedAt">>,
): Promise<void> {
  assertFgPath(FG_WAREHOUSE_GATES);
  await updateDoc(doc(db, FG_WAREHOUSE_GATES, id), {
    ...data,
    updatedAt: serverTimestamp(),
  });
}

export async function deactivateGate(id: string): Promise<void> {
  assertFgPath(FG_WAREHOUSE_GATES);
  await updateDoc(doc(db, FG_WAREHOUSE_GATES, id), {
    isActive: false,
    updatedAt: serverTimestamp(),
  });
}

