"use client";

/**
 * FleetGuard — Post-login role redirect
 *
 * After Firebase Auth sign-in, the user lands here. This page waits for
 * useAuth to resolve the fg_users profile, then pushes to the correct
 * role home. This avoids the LoginForm having to guess the role from the
 * email address.
 */

import { useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "../../_hooks/useAuth";
import type { UserRole } from "../../_lib/types";

const ROLE_HOME: Record<UserRole, string> = {
  super_admin:      "/superadmin",
  company_admin:    "/company",
  guard:            "/guard",
  wh_manager:       "/manager",
  regional_manager: "/manager",
  cso:              "/cso",
};

export default function AuthRedirectPage() {
  const { fgUser, loading, error } = useAuth();
  const router = useRouter();

  useEffect(() => {
    if (loading) return;

    if (!fgUser) {
      // No Firebase Auth session — back to login
      router.replace("/login");
      return;
    }

    const home = ROLE_HOME[fgUser.role] ?? "/login";
    router.replace(home);
  }, [fgUser, loading, router]);

  return (
    <div className="flex min-h-screen flex-col items-center justify-center gap-3 bg-slate-50">
      {error ? (
        <>
          <p className="text-[14px] font-semibold text-danger-700">Profile load failed</p>
          <p className="max-w-xs text-center text-[12px] text-slate-500">{error}</p>
          <a
            href="/login"
            className="mt-2 text-[12.5px] font-semibold text-brand-700 hover:text-brand-800"
          >
            Back to login
          </a>
        </>
      ) : (
        <>
          {/* Spinner */}
          <svg
            className="h-7 w-7 animate-spin text-brand-600"
            viewBox="0 0 24 24"
            fill="none"
          >
            <circle
              className="opacity-25"
              cx="12" cy="12" r="10"
              stroke="currentColor" strokeWidth="4"
            />
            <path
              className="opacity-75"
              fill="currentColor"
              d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
            />
          </svg>
          <p className="text-[13px] text-slate-500">Signing you in…</p>
        </>
      )}
    </div>
  );
}

