"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { ArrowRight, Fingerprint } from "lucide-react";
import { useAuth } from "../_hooks/useAuth";

export function LoginForm() {
  const router = useRouter();
  const { signIn } = useAuth();

  const [email,    setEmail]    = useState("");
  const [password, setPassword] = useState("");
  const [error,    setError]    = useState<string | null>(null);
  const [loading,  setLoading]  = useState(false);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
      await signIn(email, password);
      // Let /auth/redirect read the fg_users role and push to the correct home
      router.push("/auth/redirect");
    } catch (err: unknown) {
      const raw = err instanceof Error ? err.message : "Sign-in failed";
      // Strip Firebase boilerplate
      const msg = raw.replace("Firebase: ", "").replace(/ \(auth\/.*\)/, "");
      setError(msg);
    } finally {
      setLoading(false);
    }
  }

  return (
    <form className="space-y-4" onSubmit={handleSubmit}>
      <label className="block">
        <span className="mb-1.5 block text-[12.5px] font-medium text-slate-700">
          Work email
        </span>
        <input
          type="email"
          placeholder="you@yourcompany.com"
          autoComplete="email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
          className="h-11 w-full rounded-lg border border-slate-300 bg-white px-3.5 text-[14px] text-slate-900 placeholder:text-slate-400 focus:border-brand-500 focus:ring-4 focus:ring-brand-500/10"
        />
      </label>

      <label className="block">
        <span className="mb-1.5 block text-[12.5px] font-medium text-slate-700">
          Password
        </span>
        <input
          type="password"
          placeholder="••••••••"
          autoComplete="current-password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
          className="h-11 w-full rounded-lg border border-slate-300 bg-white px-3.5 text-[14px] text-slate-900 placeholder:text-slate-400 focus:border-brand-500 focus:ring-4 focus:ring-brand-500/10"
        />
      </label>

      {error && (
        <p className="rounded-lg border border-red-200 bg-red-50 px-3.5 py-2.5 text-[12.5px] text-red-700">
          {error}
        </p>
      )}

      <div className="flex items-center justify-between text-[12.5px]">
        <label className="inline-flex items-center gap-2 text-slate-600">
          <input type="checkbox" className="h-3.5 w-3.5 rounded border-slate-300" />
