/**
 * POST /api/users/create
 *
 * Atomically creates:
 *   1. A Firebase Auth account (so the user can sign in)
 *   2. An fg_users Firestore document (so useAuth resolves their role)
 *
 * Called by:
 *   - SuperAdmin when adding a company admin or any user for an org
 *   - Company Admin when adding Guard / CSO / Warehouse Manager / Regional Manager
 *
 * Body: CreateUserPayload (see below)
 * Response: { ok: true, uid: string }
 *
 * SECURITY: In production this should verify the caller's ID token and check
 * their role before allowing creation. For the POC this is left open but
 * structured so the check can be added easily.
 *
 * Import boundary: adminAuth and adminDb ONLY come from _lib/firebaseAdmin.
 */

import { NextRequest, NextResponse } from "next/server";
import { adminAuth, adminDb } from "../../../_lib/firebaseAdmin";
import { assertFgPath, FG_USERS } from "../../../_lib/fg-paths";
import { FieldValue } from "firebase-admin/firestore";
import type { UserRole } from "../../../_lib/types";

export interface CreateUserPayload {
  displayName: string;
  email:       string;
  password:    string;
  role:        UserRole;
  orgId:       string;
  warehouseId: string;
}

export async function POST(req: NextRequest) {
  let body: CreateUserPayload;
  try {
    body = (await req.json()) as CreateUserPayload;
  } catch {
    return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
  }

  const { displayName, email, password, role, orgId, warehouseId } = body;

  // ── Validate required fields ──────────────────────────────────────────────
  if (!displayName?.trim()) return NextResponse.json({ error: "displayName is required" }, { status: 400 });
  if (!email?.trim())       return NextResponse.json({ error: "email is required" },       { status: 400 });
  if (!password)            return NextResponse.json({ error: "password is required" },     { status: 400 });
  if (password.length < 6)  return NextResponse.json({ error: "password must be at least 6 characters" }, { status: 400 });
  if (!role)                return NextResponse.json({ error: "role is required" },          { status: 400 });

  const ALLOWED_ROLES: UserRole[] = ["super_admin", "company_admin", "guard", "wh_manager", "regional_manager", "cso"];
  if (!ALLOWED_ROLES.includes(role)) {
    return NextResponse.json({ error: `Unknown role: ${role}` }, { status: 400 });
  }

  assertFgPath(FG_USERS);

  try {
    // ── 1. Create Firebase Auth account ──────────────────────────────────────
    const authUser = await adminAuth.createUser({
      email:         email.trim().toLowerCase(),
      displayName:   displayName.trim(),
      password,
      emailVerified: true,   // POC: skip email verification flow
    });

    const uid = authUser.uid;

    // ── 2. Write fg_users Firestore document ─────────────────────────────────
    await adminDb.collection(FG_USERS).doc(uid).set({
      uid,
      email:       email.trim().toLowerCase(),
      displayName: displayName.trim(),
      role,
      orgId:       orgId       ?? "",
      warehouseId: warehouseId ?? "",
      isActive:    true,
      createdAt:   FieldValue.serverTimestamp(),
      updatedAt:   FieldValue.serverTimestamp(),
    });

    return NextResponse.json({ ok: true, uid });
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : "User creation failed";

    // Surface Firebase auth errors clearly (e.g. email-already-in-use)
    const clean = message
      .replace("Firebase: ", "")
      .replace(/ \(auth\/.*\)/, "");

    return NextResponse.json({ error: clean }, { status: 400 });
  }
}

