"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { Eye, EyeOff, Pencil, Plus, Search, UserX } from "lucide-react";
import { TopBar } from "../../../../_components/TopBar";
import { Card } from "../../../../_components/Card";
import { Badge } from "../../../../_components/Badge";
import { Button } from "../../../../_components/Button";
import { Avatar } from "../../../../_components/Avatar";
import { CompanyTabs } from "../../../../_components/CompanyTabs";
import { SlidePanel, Field, inputCls } from "../../../../_components/SlidePanel";
import { fmtDate } from "../../../../_lib/utils";
import {
  getOrganisationById,
  getUsersByOrg,
  updateUser,
  deactivateUser,
  getWarehousesByOrg,
} from "../../../../_services";
import type { FgOrganisation } from "../../../../_services/organisationService";
import type { FgUser } from "../../../../_services/userService";
import type { UserRole } from "../../../../_lib/types";
import type { CreateUserPayload } from "../../../../api/users/create/route";

const ROLES: { value: UserRole; label: string }[] = [
  { value: "company_admin",    label: "Company Admin"      },
  { value: "guard",            label: "Guard"              },
  { value: "wh_manager",       label: "Warehouse Manager"  },
  { value: "regional_manager", label: "Regional Manager"   },
  { value: "cso",              label: "CSO"                },
];

const ROLE_TONE: Record<string, "info" | "brand" | "warning" | "success" | "muted" | "danger"> = {
  company_admin:    "danger",
  guard:            "info",
  wh_manager:       "brand",
  regional_manager: "warning",
  cso:              "success",
};

const BLANK_USER = {
  displayName: "", email: "", password: "", role: "guard" as UserRole,
  warehouseId: "", orgId: "", isActive: true,
};

export default function CompanyUsersPage() {
  const { orgId } = useParams() as { orgId: string };

  const [org,        setOrg]        = useState<FgOrganisation | null>(null);
  const [users,      setUsers]      = useState<FgUser[]>([]);
  const [warehouses, setWarehouses] = useState<{ id: string; name: string }[]>([]);
  const [loading,    setLoading]    = useState(true);
  const [search,     setSearch]     = useState("");

  const [panelOpen,    setPanelOpen]    = useState(false);
  const [editing,      setEditing]      = useState<FgUser | null>(null);
  const [form,         setForm]         = useState(BLANK_USER);
  const [errors,       setErrors]       = useState<Partial<typeof BLANK_USER>>({});
  const [saving,       setSaving]       = useState(false);
  const [saveError,    setSaveError]    = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);

  const load = () => {
    if (!orgId) return;
    setLoading(true);
    Promise.all([
      getOrganisationById(orgId),
      getUsersByOrg(orgId),
      getWarehousesByOrg(orgId),
    ])
      .then(([o, u, w]) => {
        setOrg(o);
        setUsers(u);
        setWarehouses(w.map((wh) => ({ id: wh.id, name: wh.name })));
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  useEffect(load, [orgId]);

  function openCreate() {
    setEditing(null);
    setForm({ ...BLANK_USER, orgId });
    setErrors({});
    setSaveError(null);
    setShowPassword(false);
    setPanelOpen(true);
  }

  function openEdit(user: FgUser) {
    setEditing(user);
    setForm({
      displayName: user.displayName,
      email:       user.email,
      password:    "",
      role:        user.role as UserRole,
      warehouseId: user.warehouseId,
      orgId:       user.orgId,
      isActive:    user.isActive,
    });
    setErrors({});
    setSaveError(null);
    setPanelOpen(true);
  }

  function validate() {
    const e: Partial<typeof BLANK_USER> = {};
    if (!form.displayName.trim()) e.displayName = "Required";
    if (!editing) {
      if (!form.email.trim())     e.email       = "Required";
      if (!form.password)         e.password    = "Required";
      else if (form.password.length < 6) e.password = "At least 6 characters";
    }
    setErrors(e);
    return Object.keys(e).length === 0;
  }

  async function save() {
    if (!validate()) return;
    setSaving(true);
    setSaveError(null);
    try {
      if (editing) {
        // Edit: only update Firestore fields (password reset is a separate flow)
        await updateUser(editing.uid, {
          displayName: form.displayName,
          role:        form.role,
          warehouseId: form.warehouseId,
          isActive:    form.isActive,
        });
      } else {
        // Create: call API to create Firebase Auth + fg_users atomically
        const payload: CreateUserPayload = {
          displayName: form.displayName,
          email:       form.email,
          password:    form.password,
          role:        form.role,
          orgId,
          warehouseId: form.warehouseId,
        };
        const res = await fetch("/api/users/create", {
          method:  "POST",
          headers: { "Content-Type": "application/json" },
          body:    JSON.stringify(payload),
        });
        const json = await res.json() as { ok?: boolean; error?: string };
        if (!res.ok) throw new Error(json.error ?? "User creation failed");
      }
      setPanelOpen(false);
      load();
    } catch (err: unknown) {
      setSaveError(err instanceof Error ? err.message : "Failed to save user");
    } finally {
      setSaving(false);
    }
  }

  async function deactivate(uid: string) {
    await deactivateUser(uid);
    load();
  }

  const filtered = users.filter((u) => {
    const q = search.toLowerCase();
    return (
      u.displayName.toLowerCase().includes(q) ||
      u.email.toLowerCase().includes(q) ||
      u.role.toLowerCase().includes(q)
    );
  });

  return (
    <>
      <TopBar
        breadcrumbs={[
          { label: "Super Admin",  href: "/superadmin" },
          { label: "Companies",    href: "/superadmin/companies" },
          { label: org?.name ?? "…", href: `/superadmin/companies/${orgId}` },
          { label: "Users" },
        ]}
      />
      <CompanyTabs orgId={orgId} org={org} />

      <div className="flex-1 overflow-y-auto px-8 py-6">
        {/* Search + add */}
        <div className="flex flex-wrap items-center justify-between gap-3 rounded-xl border border-slate-200 bg-white p-4 shadow-xs">
          <div className="relative w-full max-w-sm">
            <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400" />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search by name, email or role…"
              className="h-10 w-full rounded-lg border border-slate-200 bg-slate-50 pl-9 pr-3 text-[13px] focus:border-brand-500 focus:bg-white focus:outline-none focus:ring-4 focus:ring-brand-500/10"
            />
          </div>
          <Button size="sm" leftIcon={<Plus className="h-3.5 w-3.5" />} onClick={openCreate}>
            Add user
          </Button>
        </div>

        <Card className="mt-4" padded={false}>
          {loading ? (
            <p className="py-10 text-center text-[13px] text-slate-500">Loading…</p>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-[10.5px] font-semibold uppercase tracking-wider text-slate-500">
                  <tr>
