                          <Button size="sm" variant="ghost" leftIcon={<Pencil className="h-3.5 w-3.5" />} onClick={() => openEdit(user)}>Edit</Button>
                          {user.isActive && (
                            <Button size="sm" variant="ghost" leftIcon={<UserX className="h-3.5 w-3.5" />} onClick={() => deactivate(user.uid)}>
                              Deactivate
