const BLANK = {
  displayName: "", email: "", password: "",
  role: "guard" as UserRole, warehouseId: "", orgId: "", isActive: true,
};

export default function CompanyUsersPage() {
  const { fgUser } = useAuth();
  const orgId = fgUser?.orgId ?? "";

  const [users,      setUsers]      = useState<FgUser[]>([]);
  const [warehouses, setWarehouses] = useState<{ id: string; name: string }[]>([]);
  const [loading,    setLoading]    = useState(true);
  const [search,     setSearch]     = useState("");

  const [panelOpen,    setPanelOpen]    = useState(false);
  const [editing,      setEditing]      = useState<FgUser | null>(null);
  const [form,         setForm]         = useState(BLANK);
  const [errors,       setErrors]       = useState<Partial<typeof BLANK>>({});
  const [saving,       setSaving]       = useState(false);
  const [saveError,    setSaveError]    = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);

  const load = () => {
    if (!orgId) return;
    setLoading(true);
    Promise.all([getUsersByOrg(orgId), getWarehousesByOrg(orgId)])
      .then(([u, w]) => {
        setUsers(u);
        setWarehouses(w.map((wh) => ({ id: wh.id, name: wh.name })));
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  };
  useEffect(load, [orgId]);

  function openCreate() {
    setEditing(null);
    setForm({ ...BLANK, orgId });
    setErrors({});
    setSaveError(null);
    setShowPassword(false);
    setPanelOpen(true);
  }

  function openEdit(user: FgUser) {
    setEditing(user);
    setForm({
      displayName: user.displayName,
      email:       user.email,
      password:    "",
      role:        user.role as UserRole,
      warehouseId: user.warehouseId,
      orgId:       user.orgId,
      isActive:    user.isActive,
    });
    setErrors({});
    setSaveError(null);
    setPanelOpen(true);
  }

  function validate() {
    const e: Partial<typeof BLANK> = {};
    if (!form.displayName.trim()) e.displayName = "Required";
    if (!editing) {
      if (!form.email.trim())    e.email    = "Required";
      if (!form.password)        e.password = "Required";
      else if (form.password.length < 6) e.password = "At least 6 characters";
    }
    setErrors(e);
    return Object.keys(e).length === 0;
  }

  async function save() {
    if (!validate()) return;
    setSaving(true);
    setSaveError(null);
    try {
      if (editing) {
        await updateUser(editing.uid, {
          displayName: form.displayName,
          role:        form.role,
          warehouseId: form.warehouseId,
          isActive:    form.isActive,
        });
      } else {
        const payload: CreateUserPayload = {
          displayName: form.displayName,
          email:       form.email,
          password:    form.password,
          role:        form.role,
          orgId,
          warehouseId: form.warehouseId,
        };
        const res = await fetch("/api/users/create", {
          method:  "POST",
          headers: { "Content-Type": "application/json" },
