        });
        const json = await res.json() as { ok?: boolean; error?: string };
        if (!res.ok) throw new Error(json.error ?? "User creation failed");
      }
      setPanelOpen(false);
      load();
    } catch (err: unknown) {
      setSaveError(err instanceof Error ? err.message : "Failed to save user");
    } finally {
      setSaving(false);
    }
  }

  const filtered = users.filter((u) => {
    const q = search.toLowerCase();
    return (
      u.displayName.toLowerCase().includes(q) ||
      u.email.toLowerCase().includes(q) ||
      u.role.toLowerCase().includes(q)
    );
  });

  return (
    <>
      <TopBar breadcrumbs={[{ label: "My Company", href: "/company" }, { label: "Users" }]} />
      <PageHeader
        eyebrow="Manage · Users"
        title="Users"
        subtitle="Create and manage user accounts for your company. Each user gets a real login."
      />

      <div className="flex-1 overflow-y-auto px-8 py-6">
        <div className="flex flex-wrap items-center justify-between gap-3 rounded-xl border border-slate-200 bg-white p-4 shadow-xs">
          <div className="relative w-full max-w-sm">
            <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400" />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search by name, email or role…"
              className="h-10 w-full rounded-lg border border-slate-200 bg-slate-50 pl-9 pr-3 text-[13px] focus:border-brand-500 focus:bg-white focus:outline-none focus:ring-4 focus:ring-brand-500/10"
            />
          </div>
          <Button size="sm" leftIcon={<Plus className="h-3.5 w-3.5" />} onClick={openCreate}>
            Add user
          </Button>
        </div>

        <Card className="mt-4" padded={false}>
          {loading ? (
            <p className="py-10 text-center text-[13px] text-slate-500">Loading…</p>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-[10.5px] font-semibold uppercase tracking-wider text-slate-500">
                  <tr>
                    <th className="px-5 py-3">User</th>
                    <th className="px-5 py-3">Role</th>
                    <th className="px-5 py-3">Warehouse</th>
                    <th className="px-5 py-3">Status</th>
                    <th className="px-5 py-3">Created</th>
                    <th className="px-5 py-3 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="text-[13px]">
                  {filtered.length === 0 ? (
                    <tr>
                      <td colSpan={6} className="py-12 text-center text-[13px] text-slate-500">
                        No users yet. Click "Add user" to create the first one.
                      </td>
                    </tr>
                  ) : filtered.map((user) => (
                    <tr key={user.uid} className="border-t border-slate-100 hover:bg-slate-50">
                      <td className="px-5 py-4">
                        <div className="flex items-center gap-3">
                          <Avatar name={user.displayName} size="sm" />
                          <div>
                            <div className="font-semibold text-slate-900">{user.displayName}</div>
                            <div className="text-[11px] text-slate-500">{user.email}</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-5 py-4">
                        <Badge tone={ROLE_TONE[user.role] ?? "muted"}>
                          {ROLES.find((r) => r.value === user.role)?.label ?? user.role}
                        </Badge>
                      </td>
                      <td className="px-5 py-4 font-mono text-[11px] text-slate-500">
                        {warehouses.find((w) => w.id === user.warehouseId)?.name ?? (user.warehouseId || "—")}
                      </td>
                      <td className="px-5 py-4">
                        <Badge tone={user.isActive ? "success" : "muted"} dot>
                          {user.isActive ? "Active" : "Inactive"}
                        </Badge>
                      </td>
                      <td className="px-5 py-4 text-[11px] text-slate-500">{fmtDate(user.createdAt)}</td>
                      <td className="px-5 py-4 text-right">
                        <div className="inline-flex items-center gap-2">
                          <Button size="sm" variant="ghost" leftIcon={<Pencil className="h-3.5 w-3.5" />} onClick={() => openEdit(user)}>
                            Edit
                          </Button>
                          {user.isActive && user.role !== "company_admin" && (
                            <Button
                              size="sm"
                              variant="ghost"
                              leftIcon={<UserX className="h-3.5 w-3.5" />}
                              onClick={() => deactivateUser(user.uid).then(load)}
                            >
                              Deactivate
                            </Button>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
          <div className="border-t border-slate-100 px-5 py-3 text-[11.5px] text-slate-500">
            {filtered.length} user{filtered.length !== 1 ? "s" : ""} shown
          </div>
        </Card>
      </div>

      <SlidePanel
        open={panelOpen}
        onClose={() => setPanelOpen(false)}
        title={editing ? "Edit user" : "Add user"}
        subtitle={
          editing
            ? `Editing ${editing.displayName}`
            : "Creates a login account + role for your company"
        }
      >
        <div className="space-y-4">
          <Field label="Full name" required error={errors.displayName}>
            <input
              className={inputCls(errors.displayName)}
              value={form.displayName}
              onChange={(e) => setForm((f) => ({ ...f, displayName: e.target.value }))}
              placeholder="John Doe"
            />
          </Field>

          {!editing && (
            <>
              <Field label="Email address" required error={errors.email}>
                <input
                  type="email"
                  className={inputCls(errors.email)}
                  value={form.email}
                  onChange={(e) => setForm((f) => ({ ...f, email: e.target.value }))}
                  placeholder="guard@company.com"
                />
              </Field>

              <Field label="Password" required error={errors.password}>
                <div className="relative">
                  <input
                    type={showPassword ? "text" : "password"}
                    className={inputCls(errors.password) + " pr-10"}
                    value={form.password}
                    onChange={(e) => setForm((f) => ({ ...f, password: e.target.value }))}
                    placeholder="Min. 6 characters"
                    autoComplete="new-password"
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword((v) => !v)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
                    tabIndex={-1}
                  >
                    {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                  </button>
                </div>
                <p className="text-[11px] text-slate-400">
                  Share with the user so they can sign in at /login.
                </p>
              </Field>
            </>
          )}

          <Field label="Role" required>
            <select
              className={inputCls()}
              value={form.role}
              onChange={(e) => setForm((f) => ({ ...f, role: e.target.value as UserRole }))}
            >
              {ROLES.map((r) => <option key={r.value} value={r.value}>{r.label}</option>)}
            </select>
          </Field>

          <Field label="Assigned warehouse">
            <select
              className={inputCls()}
              value={form.warehouseId}
              onChange={(e) => setForm((f) => ({ ...f, warehouseId: e.target.value }))}
            >
              <option value="">— No warehouse —</option>
              {warehouses.map((w) => <option key={w.id} value={w.id}>{w.name}</option>)}
            </select>
          </Field>

          {editing && (
            <div className="flex items-center gap-3 rounded-lg border border-slate-200 bg-slate-50 px-4 py-3">
              <input
                id="uActive"
                type="checkbox"
                className="h-4 w-4 rounded border-slate-300"
                checked={form.isActive}
                onChange={(e) => setForm((f) => ({ ...f, isActive: e.target.checked }))}
              />
              <label htmlFor="uActive" className="text-[13px] font-medium text-slate-700">
                User is active
              </label>
            </div>
          )}

          {saveError && (
            <p className="rounded-lg border border-red-200 bg-red-50 px-3.5 py-2.5 text-[12.5px] text-red-700">
              {saveError}
            </p>
          )}

          <div className="flex gap-3 pt-2">
            <Button full size="md" onClick={save} disabled={saving}>
              {saving ? "Saving…" : editing ? "Save changes" : "Create user"}
            </Button>
            <Button full size="md" variant="secondary" onClick={() => setPanelOpen(false)}>
              Cancel
            </Button>
          </div>
        </div>
      </SlidePanel>
    </>
  );
}

